\begin{parts}
    \item Some people each recorded their favourite holiday destination.

    The results are shown in the pie chart.

    \begin{center}
    \begin{tikzpicture}[scale=1.2]
        % Pie chart
        \draw (0,0) circle (2);

        % Sectors - angles: USA=118°, Mexico=(unlabeled), Caribbean=108°, Bali=72°, Brazil=36°
        % USA starts from top
        \draw (0,0) -- (90:2);
        \draw (0,0) -- (90-118:2);
        \draw (0,0) -- (90-118-26:2);
        \draw (0,0) -- (90-118-26-108:2);
        \draw (0,0) -- (90-118-26-108-72:2);

        % Labels
        \node at (90-59:1.3) {USA};
        \node at (90-118-13:1.3) {Mexico};
        \node at (90-118-26-54:1.3) {Caribbean};
        \node at (90-118-26-108-36:1.3) {Bali};
        \node at (90-118-26-108-72-18:1.3) {Brazil};

        % Angle labels
        \node at (90-59:0.6) {$118°$};
        \node at (90-118-26-30:0.6) {$108°$};
        \node at (90-118-26-108-20:0.6) {$72°$};
        \node at (90-118-26-108-72-10:0.6) {$36°$};
    \end{tikzpicture}
    \end{center}

    \begin{subparts}
        \subpart Complete the statements about the pie chart.

        The sector angle for Mexico is \dotfill degrees.

        The most popular destination is \dotfill

        $\dfrac{1}{5}$ of the people chose \dotfill

        Three times as many people chose \dotfill as \dotfill
        \Marks{4}

        \subpart 180 people chose Bali.

        Find how many people were asked altogether.
        \AnswerLine[][]
        \Marks{2}
    \end{subparts}

    \item Mr and Mrs Baker go on holiday with their three children.

    They fly from Miami to Mexico City.

    \begin{subparts}
        \subpart The cost of each adult ticket is \$450.

        The cost of each child ticket is 70\% of the cost of an adult ticket.

        Calculate the total cost of the five tickets.
        \AnswerLine[\$][]
        \Marks{3}

        \subpart The plane leaves Miami at 09\,29.

        It arrives in Mexico City 2 hours 11 minutes later.

        The local time in Miami is 1 hour ahead of the local time in Mexico City.

        Work out the time in Mexico City when the plane arrives.
        \AnswerLine[][]
        \Marks{2}

        \subpart The family travels 38 kilometres by taxi.

        The journey costs \$3.50 plus an extra \$2.15 for each kilometre travelled.

        Find the cost of the journey.
        \AnswerLine[\$][]
        \Marks{2}

        \subpart At the end of the holiday Mr Baker changes 1335 pesos into dollars.

        The exchange rate is \$1 = 17.8 pesos.

        Find how many dollars Mr Baker receives.
        \AnswerLine[\$][]
        \Marks{2}
    \end{subparts}
\end{parts}

